/**
 * Starts a Veo video generation job. Returns 202 with a jobId that can be polled
via `/v1/video/{jobId}/status`. If `wait=true` is passed, the server polls
internally and returns 200 with the final `videoUrl` (up to 4 minutes).

Duplicate requests (same apiKey + model + prompt + duration) within 10 minutes
return the original jobId with a `duplicateOf` field and are NOT re-billed.

 * @summary Generate a video with Veo (async by default, optional synchronous wait)
 */
export const getGenerateVideoUrl = (params?: GenerateVideoParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/v1/video?${stringifiedParams}`
    : `/api/v1/video`;
};

export const generateVideo = async (
  videoRequest: VideoRequest,
  params?: GenerateVideoParams,
  options?: RequestInit,
): Promise<VideoJobResponse> => {
  return customFetch<VideoJobResponse>(getGenerateVideoUrl(params), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(videoRequest),
  });
};

